# 016-hier_mmm-fit-engine.R
# Generated by behavior-preserving split of hier_mmm.R.

extract_loo_hier_mmm <- function(fit_obj) {
  if (!requireNamespace("loo", quietly = TRUE)) {
    stop("The 'loo' package is required. Install it with install.packages('loo').")
  }
  ll <- fit_obj$fit$draws("log_lik", format = "matrix")
  loo::loo(ll)
}
fit_hier_mmm_engine <- function(data,
                                metadata_input,
                                dep_var_col,
                         group_col,
                         time_col,
                         entity_col,
                         extra_control_cols = NULL,
                         holiday_config = NULL,
                         mean_index = TRUE,
                         dep_mean_index_scope = c("group", "global"),
                         x_mean_index_scope = c("group", "global"),
                         dep_scale_col = NULL,
                         holdout_col = NULL,
                         holdout_value = TRUE,
                         holdout_last_n = 0L,
                         estimate_dvalue = FALSE,
                         curve_prior_relax = 2,
                         coef_prior_relax = 1.5,
                         min_coef_sd_abs = 0.001,
                         min_coef_sd_frac = 0.05,
                         hard_prior_precision_threshold = 1e6,
                         bound_one_sided_coef_defaults = TRUE,
                         default_positive_coef_upper = 3,
                         default_negative_coef_lower = -3,
                         default_one_sided_coef_span = 6,
                         coef_override_input = NULL,
                         context_effects = NULL,
                         context_log_multiplier_bound = 2,
                         allow_time_context = FALSE,
                         coef_hierarchy_part_indices = NULL,
                         coef_hierarchy_index_base = c("one", "zero"),
                         intercept_type = "fourier",
                         ucm_spec = list(
                           level = FALSE,
                           season = TRUE,
                           cycle = FALSE,
                           season_period = 52L,
                           season_harmonics = 2L,
                           cycle_period = 104L,
                           cycle_harmonics = 1L
                         ),
                         use_ucm_metadata = FALSE,
                         normalize_curve_x = TRUE,
                         curve_normalization_scope = c("active_train", "all_train"),
                         sample_curve_parameters = c("always", "never"),
                         sample_coef_hierarchy = c("auto", "always", "never"),
                         coef_hierarchy_auto_min_groups = 5L,
                         coef_hierarchy_auto_min_scale = 0.25,
                         coef_hierarchy_auto_min_geo_variation_share = 0.20,
                         coef_parameterization = c("noncentered", "centered", "auto"),
                         alpha_parameterization = c("noncentered", "centered", "shared"),
                         ucm_parameterization = c("noncentered", "centered"),
                         center_predictors_for_sampling = FALSE,
                         allow_negative_curve_inputs = FALSE,
                         stop_on_zero_variance = TRUE,
                         alpha_mu_prior_mean = 1,
                         alpha_mu_prior_sd = 0.5,
                         alpha_sd_prior_sd = 0.25,
                         level0_mu_prior_mean = 1,
                         level0_mu_prior_sd = 0.35,
                         level0_sd_prior_sd = 0.15,
                         sigma_level_prior_sd = 0.03,
                         season_sd_prior_sd = 0.10,
                         cycle_sd_prior_sd = 0.08,
                         gamma_prior_sd = 0.25,
                         sigma_y_prior_sd = 0.25,
                         sigma_y_floor = 0.005,
                         sigma_y_upper = 5,
                         likelihood = c("student_t", "normal"),
                         student_t_nu = 5,
                         collinearity_threshold = 0.85,
                         stan_file = NULL,
                         init_strategy = c("pathfinder", "ucm_pathfinder", "ucm", "random"),
                         use_ucm_warm_start_init = TRUE,
                         ucm_warm_start_smooth_window = 7L,
                         ucm_warm_start_jitter = 0.01,
                         use_pathfinder_init = TRUE,
                         chains = 4,
                         parallel_chains = 4,
                         iter_warmup = 1000,
                         iter_sampling = 1000,
                         adapt_delta = 0.95,
                         max_treedepth = 12,
                         metric = c("diag_e", "dense_e", "unit_e"),
                         seed = 123,
                         refresh = 100,
                         thin = 1,
                         save_warmup = FALSE,
                         sig_figs = NULL,
                         output_dir = "hier_mmm_outputs",
                         output_prefix = "",
                         verbose = TRUE,
                         checkpoint_file = NULL,
                         output_variables = "lean") {
  likelihood <- match.arg(likelihood)
  curve_normalization_scope <- normalize_curve_normalization_scope_hier_mmm(match.arg(curve_normalization_scope))
  sample_curve_parameters <- match.arg(sample_curve_parameters)
  sample_coef_hierarchy <- match.arg(sample_coef_hierarchy)
  coef_hierarchy_index_base <- match.arg(coef_hierarchy_index_base)
  coef_parameterization <- match.arg(coef_parameterization)
  alpha_parameterization <- match.arg(alpha_parameterization)
  ucm_parameterization <- match.arg(ucm_parameterization)
  metric <- match.arg(metric)
  dep_mean_index_scope <- match.arg(dep_mean_index_scope)
  x_mean_index_scope <- match.arg(x_mean_index_scope)
  stan_file <- resolve_hier_mmm_stan_file(stan_file)
  output_prefix <- output_prefix %||% ""
  if (!is.null(output_dir) && !nzchar(output_dir)) output_dir <- NULL
  if (is.null(checkpoint_file) && !is.null(output_dir) && nzchar(output_dir)) {
    pfx <- if (nzchar(output_prefix)) paste0(output_prefix, "_") else ""
    checkpoint_file <- file.path(output_dir, paste0(pfx, "run_checkpoints.log"))
  }
  checkpoint <- function(stage, status = "OK", detail = "") {
    log_hier_mmm_checkpoint(
      stage = stage,
      status = status,
      detail = detail,
      checkpoint_file = checkpoint_file,
      verbose = verbose
    )
  }

  checkpoint(
    "fit_hier_mmm start",
    detail = paste0("chains=", chains, ", warmup=", iter_warmup, ", sampling=", iter_sampling,
                    ", likelihood=", likelihood, ", init_strategy=", init_strategy[1],
                    ", sample_coef_hierarchy=", sample_coef_hierarchy,
                    ", coef_parameterization=", coef_parameterization,
                    ", alpha_parameterization=", alpha_parameterization,
                    ", ucm_parameterization=", ucm_parameterization,
                    ", center_predictors_for_sampling=", isTRUE(center_predictors_for_sampling))
  )
  checkpoint("prepare data + metadata", status = "START")

  prep <- prepare_stan_data_hier_mmm(
    data = data,
    metadata_input = metadata_input,
    dep_var_col = dep_var_col,
    group_col = group_col,
    time_col = time_col,
    entity_col = entity_col,
    extra_control_cols = extra_control_cols,
    holiday_config = holiday_config,
    mean_index = mean_index,
    dep_mean_index_scope = dep_mean_index_scope,
    x_mean_index_scope = x_mean_index_scope,
    dep_scale_col = dep_scale_col,
    holdout_col = holdout_col,
    holdout_value = holdout_value,
    holdout_last_n = holdout_last_n,
    estimate_dvalue = estimate_dvalue,
    curve_prior_relax = curve_prior_relax,
    coef_prior_relax = coef_prior_relax,
    min_coef_sd_abs = min_coef_sd_abs,
    min_coef_sd_frac = min_coef_sd_frac,
    hard_prior_precision_threshold = hard_prior_precision_threshold,
    bound_one_sided_coef_defaults = bound_one_sided_coef_defaults,
    default_positive_coef_upper = default_positive_coef_upper,
    default_negative_coef_lower = default_negative_coef_lower,
    default_one_sided_coef_span = default_one_sided_coef_span,
    coef_override_input = coef_override_input,
    context_effects = context_effects,
    context_log_multiplier_bound = context_log_multiplier_bound,
    allow_time_context = allow_time_context,
    coef_hierarchy_part_indices = coef_hierarchy_part_indices,
    coef_hierarchy_index_base = coef_hierarchy_index_base,
    intercept_type = intercept_type,
    ucm_spec = ucm_spec,
    use_ucm_metadata = use_ucm_metadata,
    normalize_curve_x = normalize_curve_x,
    curve_normalization_scope = curve_normalization_scope,
    sample_curve_parameters = sample_curve_parameters,
    sample_coef_hierarchy = sample_coef_hierarchy,
    coef_hierarchy_auto_min_groups = coef_hierarchy_auto_min_groups,
    coef_hierarchy_auto_min_scale = coef_hierarchy_auto_min_scale,
    coef_hierarchy_auto_min_geo_variation_share = coef_hierarchy_auto_min_geo_variation_share,
    coef_parameterization = coef_parameterization,
    alpha_parameterization = alpha_parameterization,
    ucm_parameterization = ucm_parameterization,
    center_predictors_for_sampling = center_predictors_for_sampling,
    allow_negative_curve_inputs = allow_negative_curve_inputs,
    stop_on_zero_variance = stop_on_zero_variance,
    alpha_mu_prior_mean = alpha_mu_prior_mean,
    alpha_mu_prior_sd = alpha_mu_prior_sd,
    alpha_sd_prior_sd = alpha_sd_prior_sd,
    level0_mu_prior_mean = level0_mu_prior_mean,
    level0_mu_prior_sd = level0_mu_prior_sd,
    level0_sd_prior_sd = level0_sd_prior_sd,
    sigma_level_prior_sd = sigma_level_prior_sd,
    season_sd_prior_sd = season_sd_prior_sd,
    cycle_sd_prior_sd = cycle_sd_prior_sd,
    gamma_prior_sd = gamma_prior_sd,
    sigma_y_prior_sd = sigma_y_prior_sd,
    sigma_y_floor = sigma_y_floor,
    sigma_y_upper = sigma_y_upper,
    likelihood = likelihood,
    student_t_nu = student_t_nu
  )

  checkpoint(
    "prepare data + metadata",
    detail = paste0("N=", prep$stan_data$N,
                    ", train=", prep$stan_data$N_train,
                    ", holdout=", length(prep$holdout_idx),
                    ", groups=", prep$stan_data$G,
                    ", variables=", prep$stan_data$J,
                    ", curved=", prep$stan_data$J_curve,
                    ", ignored_cols=", length(prep$ignored_data_cols))
  )
  checkpoint("validate Stan data contract", detail = "dimension and index checks passed")
  validate_prior_scales(prep$stan_data, verbose = verbose)

  require_hier_mmm_pkg("cmdstanr", "fitting hierarchical MMM Stan models")
  require_hier_mmm_pkg("posterior", "fitting and summarizing hierarchical MMM Stan models")
  checkpoint("compile Stan model", status = "START", detail = stan_file)
  mod <- cmdstanr::cmdstan_model(stan_file, cpp_options = list(stan_threads = FALSE))
  checkpoint("compile Stan model", detail = "compiled successfully")

  init_strategy <- match.arg(init_strategy)
  if (identical(init_strategy, "ucm_pathfinder") && (!isTRUE(use_ucm_warm_start_init) || !isTRUE(use_pathfinder_init))) {
    if (isTRUE(use_ucm_warm_start_init)) init_strategy <- "ucm" else if (isTRUE(use_pathfinder_init)) init_strategy <- "pathfinder" else init_strategy <- "random"
  }

  ucm_init_obj <- NULL
  if (init_strategy %in% c("ucm", "ucm_pathfinder")) {
    checkpoint("build UCM-informed initialization", status = "START")
    ucm_init_obj <- build_ucm_warm_start_init(
      prep = prep,
      chains = chains,
      seed = seed,
      smooth_window = ucm_warm_start_smooth_window,
      jitter = ucm_warm_start_jitter
    )
    checkpoint("build UCM-informed initialization", detail = paste0("init chains=", length(ucm_init_obj)))
  }

  init_obj <- NULL
  pathfinder_fit <- NULL
  if (init_strategy %in% c("pathfinder", "ucm_pathfinder")) {
    checkpoint("run Pathfinder initialization", status = "START")
    pf_args <- list(data = prep$stan_data, seed = seed, refresh = refresh)
    if (init_strategy == "ucm_pathfinder") pf_args$init <- ucm_init_obj
    pathfinder_fit <- tryCatch(
      do.call(mod$pathfinder, pf_args),
      error = function(e) {
        checkpoint("run Pathfinder initialization", status = "WARN", detail = conditionMessage(e))
        warning("Pathfinder initialization failed; falling back to ", if (!is.null(ucm_init_obj)) "UCM-informed init." else "random init.", " Message: ", conditionMessage(e))
        NULL
      }
    )
    if (!is.null(pathfinder_fit)) checkpoint("run Pathfinder initialization", detail = "Pathfinder completed")
    init_obj <- pathfinder_fit %||% ucm_init_obj
  } else if (init_strategy == "ucm") {
    init_obj <- ucm_init_obj
  }

  sample_args <- list(
    data = prep$stan_data,
    init = init_obj %||% NULL,
    chains = chains,
    parallel_chains = parallel_chains,
    iter_warmup = iter_warmup,
    iter_sampling = iter_sampling,
    adapt_delta = adapt_delta,
    max_treedepth = max_treedepth,
    metric = metric,
    seed = seed,
    refresh = refresh,
    thin = thin,
    save_warmup = save_warmup
  )
  if (!is.null(sig_figs)) sample_args$sig_figs <- sig_figs
  if (!is.null(output_variables) && !identical(output_variables, "all")) {
    if (identical(output_variables, "lean")) {
      output_variables <- c(
        "beta", "rrate", "cvalue", "dvalue", "context_coef", "alpha_flat", "gamma",
        "level_component", "cycle_component", "season_component", "level_state",
        "sigma_y", "y_hat", "log_lik"
      )
    }
    sample_formals <- names(formals(mod$sample))
    if ("variables" %in% sample_formals) {
      sample_args$variables <- output_variables
      if ("include" %in% sample_formals) sample_args$include <- TRUE
    } else if ("output_variables" %in% sample_formals) {
      sample_args$output_variables <- output_variables
    } else {
      checkpoint(
        "select Stan output variables",
        status = "WARN",
        detail = "installed cmdstanr does not support draw filtering; saving all variables"
      )
      output_variables <- "all"
    }
  }
  checkpoint("run HMC/NUTS sampling", status = "START", detail = paste0("adapt_delta=", adapt_delta, ", max_treedepth=", max_treedepth, ", metric=", metric, ", output_variables=", if (is.null(output_variables)) "default" else paste(output_variables[seq_len(min(length(output_variables), 6L))], collapse = "|")))
  fit <- do.call(mod$sample, sample_args)
  checkpoint("run HMC/NUTS sampling", detail = "sampling completed")

  checkpoint("build decomposition outputs", status = "START")
  outputs <- build_outputs_hier_mmm(
    fit = fit,
    prep = prep,
    extra_control_cols = extra_control_cols
  )
  checkpoint("build decomposition outputs", detail = paste0("wide_rows=", nrow(outputs$wide_decomp), ", long_rows=", nrow(outputs$long_decomp)))

  checkpoint("build diagnostics", status = "START")
  diagnostics <- build_diagnostics_hier_mmm(
    fit = fit,
    max_treedepth = max_treedepth
  )
  diagnostics$sampler_recommendations <- recommend_hier_mmm_sampler_settings(
    diagnostics,
    current_max_treedepth = max_treedepth,
    iter_warmup = iter_warmup,
    iter_sampling = iter_sampling
  )
  fit_quality <- build_fit_quality_diagnostics(outputs$wide_decomp, prep$group_col, prep$time_col)
  diagnostics$fit_quality_overall <- fit_quality$overall
  diagnostics$fit_quality_by_group <- fit_quality$by_group

  ucm_quality <- build_ucm_component_diagnostics(outputs$wide_decomp, prep$group_col, prep$time_col)
  diagnostics$ucm_component_overall <- ucm_quality$overall
  diagnostics$ucm_component_by_group <- ucm_quality$by_group

  prior_post <- build_prior_posterior_diagnostics(fit, prep, outputs)
  diagnostics$prior_posterior_coef <- prior_post$coef
  diagnostics$prior_posterior_curve <- prior_post$curve
  diagnostics$prior_posterior_context <- prior_post$context

  collinearity <- build_collinearity_diagnostics(prep, threshold = collinearity_threshold)
  diagnostics$collinearity_overall <- collinearity$overall
  diagnostics$collinearity_by_group <- collinearity$by_group

  ucm_stealing <- build_ucm_media_stealing_diagnostics(
    wide_decomp = outputs$wide_decomp,
    variable_lookup = prep$variable_lookup,
    group_col = prep$group_col,
    time_col = prep$time_col
  )
  diagnostics$ucm_media_stealing_overall <- ucm_stealing$overall
  diagnostics$ucm_media_stealing_by_group <- ucm_stealing$by_group
  readiness <- build_hier_mmm_model_readiness(
    diagnostics = diagnostics,
    iter_warmup = iter_warmup,
    iter_sampling = iter_sampling,
    max_treedepth = max_treedepth
  )
  diagnostics$model_readiness <- readiness$summary
  diagnostics$model_readiness_issues <- readiness$issues
  checkpoint("build diagnostics", detail = paste0("sampler_flags=", nrow(diagnostics$diagnostics_flags), ", collinearity_pairs=", nrow(diagnostics$collinearity_overall)))

  if (!is.null(output_dir) && nzchar(output_dir)) {
    checkpoint("write output files", status = "START", detail = output_dir)
    write_outputs_hier_mmm(
      outputs = outputs,
      diagnostics = diagnostics,
      output_dir = output_dir,
      prefix = output_prefix
    )
    checkpoint("write output files", detail = output_dir)
  }

  checkpoint("fit_hier_mmm complete", detail = "returning fit object and outputs")

  list(
    fit = fit,
    stan_data = prep$stan_data,
    metadata = prep$metadata,
    curve_priors = prep$curve_priors,
    variable_lookup = prep$variable_lookup,
    context_effects = prep$context_effects,
    group_lookup = prep$group_lookup,
    data = prep$data,
    intercept_type = prep$intercept_type,
    intercept_spec = prep$intercept_spec,
    ucm_spec = prep$ucm_spec,
    ucm_metadata = prep$ucm_metadata,
    init_strategy = init_strategy,
    pathfinder_fit = pathfinder_fit,
    intercept_use_level = prep$intercept_use_level,
    intercept_use_cycle = prep$intercept_use_cycle,
    intercept_use_season = prep$intercept_use_season,
    normalize_curve_x = prep$normalize_curve_x,
    curve_normalization_scope = prep$curve_normalization_scope,
    sample_curve_parameters = prep$sample_curve_parameters,
    sample_coef_hierarchy = prep$sample_coef_hierarchy,
    coef_hierarchy_auto_min_groups = prep$coef_hierarchy_auto_min_groups,
    coef_parameterization = prep$coef_parameterization,
    alpha_parameterization = prep$alpha_parameterization,
    ucm_parameterization = prep$ucm_parameterization,
    center_predictors_for_sampling = prep$center_predictors_for_sampling,
    likelihood = prep$likelihood,
    student_t_nu = prep$student_t_nu,
    estimate_dvalue = prep$estimate_dvalue,
    sampler_settings = list(
      chains = chains,
      parallel_chains = parallel_chains,
      iter_warmup = iter_warmup,
      iter_sampling = iter_sampling,
      adapt_delta = adapt_delta,
      max_treedepth = max_treedepth,
      metric = metric,
      thin = thin,
      output_variables = output_variables
    ),
    min_coef_sd_abs = prep$min_coef_sd_abs,
    min_coef_sd_frac = prep$min_coef_sd_frac,
    hard_prior_precision_threshold = prep$hard_prior_precision_threshold,
    context_log_multiplier_bound = prep$context_log_multiplier_bound,
    checkpoint_file = checkpoint_file,
    ucm_prior_controls = prep$ucm_prior_controls,
    holiday_control_audit = prep$holiday_control_audit,
    holiday_config = prep$holiday_config,
    ignored_data_cols = prep$ignored_data_cols,
    holdout_col = prep$holdout_col,
    holdout_last_n = prep$holdout_last_n,
    group_col = prep$group_col,
    time_col = prep$time_col,
    entity_col = prep$entity_col,
    dep_var_col = prep$dep_var_col,
    train_idx = prep$train_idx,
    holdout_idx = prep$holdout_idx,
    coef_override_long = prep$coef_override_long,
    coef_by_group = outputs$coef_by_group,
    coef_by_mod_id = outputs$coef_by_mod_id,
    coef_long = outputs$coef_long,
    wide_decomp = outputs$wide_decomp,
    long_decomp = outputs$long_decomp,
    diagnostics = diagnostics
  )
}

